async function productRoutes (fastify) {
	fastify.get('/:_id', async (req, res) => {
		req.log.info('get one products from db');
		const product = await fastify.db.products.findOne(req.params._id);
		res.send(product);
	});

	fastify.get('/', async (req, res) => {
		req.log.info('list products from db');
		const products = await fastify.db.products.find();
		res.send(products);
	});

	fastify.post('/', async (req, res) => {
		req.log.info('Add products to db');
		const products = await fastify.db.products.save(req.body);
		res.status(201).send(products);
	});

	fastify.put('/:_id', async (req, res) => {
		req.log.info('Update product to db');
		const _id = req.params._id;
		const products = await fastify.db.products.save({ _id, ...req.body });
		res.status(200).send(products);
	});

	fastify.delete('/:_id', async (req, res) => {
		req.log.info(`delete product ${req.params._id} from db`);
		const product = await fastify.db.products.findOne(req.params._id);
		await fastify.db.products.remove(product);
		res.code(200).send({});
	});
}

module.exports = productRoutes;

import type { FastifyPluginAsyncTypebox } from '@fastify/type-provider-typebox';
import { Type } from 'typebox';

import useTableControl from '~/composables/useTableControl.ts';

import { RoleBox, UserBox } from './schema.ts';

export default (async (app) => {
  app.post(
    '',
    {
      schema: {
        response: {
          200: Type.Object({
            message: Type.String(),
            result: Type.Array(Type.Intersect([Type.Partial(UserBox), Type.Partial(RoleBox)])),
            total: Type.Number(),
          }),
        },
      },
    },
    async (request, reply) => {
      const users = app.mongo.db?.collection('users');

      const { page, rows, field, direction } = useTableControl(request);

      const conditions = {};

      const result = await users
        ?.find(conditions)
        .project({ password: 0, secret: 0 })
        .sort(field, direction)
        .limit(rows)
        .skip(rows * (page - 1))
        .toArray();

      const total = await users?.countDocuments(conditions);

      return reply.send({
        message: 'OK',
        result: result || [],
        total: total || 0,
      });
    },
  );
}) as FastifyPluginAsyncTypebox;

