'use strict'

const validate = require('./config-validator')
const deepClone = require('rfdc')({ circles: true, proto: false })
const { FST_ERR_INIT_OPTS_INVALID } = require('./errors')

function validateInitialConfig (options) {
  const opts = deepClone(options)

  if (!validate(opts)) {
    const error = new FST_ERR_INIT_OPTS_INVALID(JSON.stringify(validate.errors.map(e => e.message)))
    error.errors = validate.errors
    throw error
  }

  return deepFreezeObject(opts)
}

function deepFreezeObject (object) {
  const properties = Object.getOwnPropertyNames(object)

  for (const name of properties) {
    const value = object[name]

    if (ArrayBuffer.isView(value) && !(value instanceof DataView)) {
      continue
    }

    object[name] = value && typeof value === 'object' ? deepFreezeObject(value) : value
  }

  return Object.freeze(object)
}

module.exports = validateInitialConfig
module.exports.defaultInitOptions = validate.defaultInitOptions
module.exports.utils = { deepFreezeObject }

import createError from 'http-errors';
import { getAllowedMethods } from '../../configurations';
import type { FastifyRequest } from 'fastify';

export default {
  validateAllowedMethods: {
    event: 'onRequest',
    handler: function(routeOptions, route) {
      return async function(request: FastifyRequest): Promise<void> {
        const allowedMethods = getAllowedMethods(this.config);
        const handlerKey = Object.keys(routeOptions).find(
          (key) =>
            routeOptions[key].method === request.routerMethod &&
            routeOptions[key].url === request.routerPath.replace(route || '/', '')
        );

        if (handlerKey && !allowedMethods.includes(handlerKey as any)) {
          throw createError(405, `Method ${request.routerMethod} is not allowed here`);
        }
      };
    }
  }
};

import type { IncomingHttpHeaders } from "node:http";

import { HTTPGraphQLRequest, HeaderMap } from "@apollo/server";
import type { FastifyRequest, RawServerBase, RawServerDefault, RouteGenericInterface } from "fastify";

const httpHeadersToMap = (headers: IncomingHttpHeaders) => {
	const map = new HeaderMap();

	for (const [key, value] of Object.entries(headers)) {
		if (value) {
			map.set(key, Array.isArray(value) ? value.join(", ") : value);
		}
	}

	return map;
};

export const fastifyRequestToGraphQLRequest = <RawServer extends RawServerBase = RawServerDefault>(
	request: FastifyRequest<RouteGenericInterface, RawServer>,
): HTTPGraphQLRequest => ({
	body: request.body,
	method: request.method.toUpperCase(),
	headers: httpHeadersToMap(request.headers),
	search: new URL(request.url, `${request.protocol}://${request.hostname}/`).search,
});

